describe('AutocompletePrompt async options', () => {
	let input: MockReadable;
	let output: MockWritable;
	const testOptions = [
		{ value: 'apple', label: 'Apple' },
		{ value: 'banana', label: 'Banana' },
		{ value: 'cherry', label: 'Cherry' },
	];

	beforeEach(() => {
		input = new MockReadable();
		output = new MockWritable();
		vi.useFakeTimers();
	});

	afterEach(() => {
		vi.useRealTimers();
		vi.restoreAllMocks();
	});

	test('detects an async resolver and applies the first fetch result', async () => {
		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: () => Promise.resolve(testOptions),
		});

		expect(instance.loading).to.equal(true);
		instance.prompt();

		await vi.runOnlyPendingTimersAsync();
		await Promise.resolve();
		await Promise.resolve();

		expect(instance.loading).to.equal(false);
		expect(instance.filteredOptions).to.deep.equal(testOptions);
	});

	test('async detection works for zero-parameter async functions', async () => {
		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: async () => testOptions,
		});

		instance.prompt();
		await Promise.resolve();
		await Promise.resolve();

		expect(instance.filteredOptions).to.deep.equal(testOptions);
	});

	test('debounces fetches triggered by user input', async () => {
		const fetchFn = vi.fn((search: string) => Promise.resolve(testOptions.filter((o) => o.value.includes(search))));
		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchFn,
			debounceMs: 100,
		});

		instance.prompt();
		await Promise.resolve();
		await Promise.resolve();
		fetchFn.mockClear();

		input.emit('keypress', 'a', { name: 'a' });
		await vi.advanceTimersByTimeAsync(50);
		input.emit('keypress', 'p', { name: 'p' });
		await vi.advanceTimersByTimeAsync(50);

		// Still within debounce window of the last keystroke; no fetch yet
		expect(fetchFn).not.toHaveBeenCalled();

		await vi.advanceTimersByTimeAsync(100);
		expect(fetchFn).toHaveBeenCalledTimes(1);
		expect(fetchFn).toHaveBeenCalledWith('ap', expect.objectContaining({ signal: expect.anything() }));
	});

	test('aborts the previous fetch when a new one starts', async () => {
		const signals: AbortSignal[] = [];
		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			debounceMs: 10,
			options: (_search: string, ctx: { signal: AbortSignal }) => {
				signals.push(ctx.signal);
				return new Promise(() => {
					/* never resolves */
				});
			},
		});

		instance.prompt();
		input.emit('keypress', 'a', { name: 'a' });
		await vi.advanceTimersByTimeAsync(10);
		input.emit('keypress', 'p', { name: 'p' });
		await vi.advanceTimersByTimeAsync(10);

		expect(signals.length).to.equal(3); // initial detection call + 2 searches
		expect(signals[0].aborted).to.equal(true);
		expect(signals[1].aborted).to.equal(true);
		expect(signals[2].aborted).to.equal(false);
	});

	test('discards stale results when a newer fetch resolves first', async () => {
		let resolveFirst: (value: typeof testOptions) => void = () => {};
		const firstPromise = new Promise<typeof testOptions>((res) => {
			resolveFirst = res;
		});

		let callIndex = 0;
		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			debounceMs: 0,
			options: (search: string) => {
				callIndex++;
				if (callIndex === 1) return firstPromise;
				return Promise.resolve(testOptions.filter((o) => o.value.includes(search)));
			},
		});

		instance.prompt();
		await Promise.resolve();
		await Promise.resolve();

		input.emit('keypress', 'b', { name: 'b' });
		await vi.advanceTimersByTimeAsync(0);
		await Promise.resolve();
		await Promise.resolve();

		// Second (later) fetch resolves first, applying banana-only results
		expect(instance.filteredOptions).to.deep.equal([{ value: 'banana', label: 'Banana' }]);

		// Now the stale first fetch resolves; it must not override current state
		resolveFirst(testOptions);
		await Promise.resolve();
		await Promise.resolve();

		expect(instance.filteredOptions).to.deep.equal([{ value: 'banana', label: 'Banana' }]);
	});

