		input = new MockReadable();
		output = new MockWritable();
	});

	afterEach(() => {
		vi.restoreAllMocks();
	});

	test('shows the loading message while an async fetch is in flight', async () => {
		let resolveFetch: (value: typeof testOptions) => void = () => {};
		const result = autocomplete({
			message: 'Select a fruit',
			options: () => new Promise((res) => (resolveFetch = res)),
			loadingMessage: 'Fetching fruits…',
			input,
			output,
		});

		const rendered = output.buffer.join('');
		expect(rendered).toContain('Fetching fruits…');

		resolveFetch(testOptions);
		await Promise.resolve();
		await Promise.resolve();
		input.emit('keypress', '', { name: 'return' });
		await result;
	});

